// frontend/src/pages/PostPage.js
import React, { useState, useEffect } from 'react';
import { useParams, Link } from 'react-router-dom';
import API from '../api/axios';

const PostPage = () => {
  const { id } = useParams();
  const [post, setPost] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    API.get(`/posts/${id}`)
      .then(res => {
        setPost(res.data);
        setLoading(false);
      })
      .catch(err => {
        console.error(err);
        setLoading(false);
      });
  }, [id]);

  if (loading) return <p>Loading post...</p>;
  if (!post) return <p>Post not found.</p>;

  return (
    <main className="post-page">
      <h1>{post.title}</h1>
      <small>By {post.author?.name} on {new Date(post.createdAt).toLocaleDateString()}</small>
      
      {post.image && (
        <img src={`http://localhost:5000/uploads/${post.image}`} alt={post.title} style={{maxWidth: '100%', marginTop: '20px'}} />
      )}
      
      <div className="post-body" style={{marginTop: '20px', whiteSpace: 'pre-wrap'}}>
        {post.body}
      </div>

      <Link to="/home" style={{display: 'inline-block', marginTop: '30px'}}>← Back to Home</Link>
    </main>
  );
};

export default PostPage;
